const BASE = 'https://api.normies.art';

// 1. Find the agent's Normie tokens
const { tokenIds } = await fetch(`${BASE}/holders/${agent}`).then(r => r.json());

for (const id of tokenIds) {
  // 2. Pull the deterministic persona (regenerated live from canvas state)
  const persona = await fetch(`${BASE}/agents/info/${id}`).then(r => r.json());
  console.log(`#${id} -> ${persona.name}: "${persona.tagline}"`);

  // 3. Get the A2A Agent Card for inter-agent discovery
  const card = await fetch(`${BASE}/agents/agent-card/${id}`).then(r => r.json());

  // 4. Confirm ERC-8004 binding via Adapter8004
  const binding = await fetch(`${BASE}/agents/binding/${id}`).then(r => r.json());
  if (!binding.bound) console.warn(`#${id} is not yet awakened`);
}

